type AppVersionProxy struct {
	devportal.UnimplementedAppVersionServer
	client devportal.AppVersionClient
}

func init() {
	proxyutil.Register(&devportal.AppVersion_ServiceDesc, NewAppVersionProxy)
}
func NewAppVersionProxy(cc grpc.ClientConnInterface) devportal.AppVersionServer {
	return &AppVersionProxy{client: devportal.NewAppVersionClient(cc)}
}
func (p *AppVersionProxy) Create(ctx context.Context, in *appversion.AppVersionCreationRequest) (*info.AppVersionInfo, error) {
	return proxyutil.ProxyMethod[appversion.AppVersionCreationRequest, info.AppVersionInfo](p.client.Create)(ctx, in)
}
func (p *AppVersionProxy) Get(ctx context.Context, in *devvit.UUID) (*appversion.FullAppVersionInfo, error) {
	return proxyutil.ProxyMethod[devvit.UUID, appversion.FullAppVersionInfo](p.client.Get)(ctx, in)
}
func (p *AppVersionProxy) GetBySlugAndVersionNumber(ctx context.Context, in *appversion.AppSlugAndVersion) (*appversion.FullAppVersionInfo, error) {
	return proxyutil.ProxyMethod[appversion.AppSlugAndVersion, appversion.FullAppVersionInfo](p.client.GetBySlugAndVersionNumber)(ctx, in)
}
func (p *AppVersionProxy) Update(ctx context.Context, in *appversion.AppVersionUpdateRequest) (*appversion.FullAppVersionInfo, error) {
	return proxyutil.ProxyMethod[appversion.AppVersionUpdateRequest, appversion.FullAppVersionInfo](p.client.Update)(ctx, in)
}
func (p *AppVersionProxy) GetValidInstallLocations(ctx context.Context, in *appversion.ValidInstallLocationsRequest) (*appversion.ValidInstallLocationsResponse, error) {
	return proxyutil.ProxyMethod[appversion.ValidInstallLocationsRequest, appversion.ValidInstallLocationsResponse](p.client.GetValidInstallLocations)(ctx, in)
}
func (p *AppVersionProxy) GetAppVersionBundle(ctx context.Context, in *devvit.UUID) (*appversion.GetAppVersionBundleResponse, error) {
	return proxyutil.ProxyMethod[devvit.UUID, appversion.GetAppVersionBundleResponse](p.client.GetAppVersionBundle)(ctx, in)
}
func (p *AppVersionProxy) GetNutritionByNameVersion(ctx context.Context, in *nutrition.GetNutritionByNameVersionRequest) (*nutrition.MultipleNutritionCategories, error) {
	return proxyutil.ProxyMethod[nutrition.GetNutritionByNameVersionRequest, nutrition.MultipleNutritionCategories](p.client.GetNutritionByNameVersion)(ctx, in)
}
func (p *AppVersionProxy) GetNutritionByAppVersionId(ctx context.Context, in *devvit.UUID) (*nutrition.MultipleNutritionCategories, error) {
	return proxyutil.ProxyMethod[devvit.UUID, nutrition.MultipleNutritionCategories](p.client.GetNutritionByAppVersionId)(ctx, in)
}
